111→/// Returns `false` for model IDs that are clearly not chat-completion models
112→/// (image generators, TTS, speech-to-text, embeddings, moderation, etc.).
113→///
114→/// Provider APIs like OpenAI's `/v1/models` return every model in the account.
115→/// Since no capability metadata is exposed we filter by well-known prefixes and
116→/// patterns. This is applied both at discovery time and at display time so that
117→/// non-chat models never appear in the UI.
118→pub fn is_chat_capable_model(model_id: &str) -> bool {
119→    let id = capability_model_id(model_id);
120→    const NON_CHAT_PREFIXES: &[&str] = &[
121→        "dall-e",
122→        "gpt-image",
123→        "chatgpt-image",
124→        "gpt-audio",
125→        "tts-",
126→        "whisper",
127→        "text-embedding",
128→        "claude-embedding",
129→        "claude-embeddings",
130→        "omni-moderation",
131→        "moderation-",
132→        "sora",
133→        // Google Gemini non-chat models
134→        "imagen-",
135→        "gemini-embedding",
136→        "learnlm-",
137→        "gemma-3n-",
138→        // Z.AI non-chat models
139→        "glm-image",
140→        "glm-asr",
141→        "glm-ocr",
142→        "cogvideo",
143→        "cogview",
144→        "vidu",
145→        "autoglm-phone",
146→    ];
147→    for prefix in NON_CHAT_PREFIXES {
148→        if id.starts_with(prefix) {
149→            return false;
150→        }
151→    }
152→    // TTS / audio-only / realtime / transcription variants
153→    if id.contains("-tts") || id.contains("-audio-") || id.ends_with("-audio") {
154→        return false;
155→    }
156→    if id.contains("-realtime-") || id.ends_with("-realtime") {
157→        return false;
158→    }
159→    if id.contains("-transcribe") {
160→        return false;
161→    }
162→    // Gemini live (real-time dialogue) and image-generation variants
163→    if id.contains("-live-") || id.contains("-image-") {
164→        return false;
165→    }
166→    true
167→}
168→
169→/// Check if a model supports tool/function calling.
170→///
171→/// Most modern chat models support tools, but legacy completions-only models
172→/// (e.g. `babbage-002`, `davinci-002`) and non-chat models do not.
173→/// This is checked per-model rather than per-provider so that providers
174→/// exposing mixed catalogs report accurate tool support.
175→pub fn supports_tools_for_model(model_id: &str) -> bool {
176→    let id = capability_model_id(model_id);
177→    // Legacy completions-only models — no tool support
178→    if id.starts_with("babbage") || id.starts_with("davinci") {
179→        return false;
180→    }
181→    // Non-chat model families — never support tools
182→    if id.starts_with("dall-e")
183→        || id.starts_with("gpt-image")
184→        || id.starts_with("tts-")
185→        || id.starts_with("whisper")
186→        || id.starts_with("text-embedding")
187→        || id.starts_with("claude-embedding")
188→        || id.starts_with("claude-embeddings")
189→        || id.starts_with("omni-moderation")
190→    {
191→        return false;
192→    }
193→    // Default: assume tool support for modern chat models
194→    true
195→}
196→
197→/// Check if a model supports vision (image inputs).
198→///
199→/// Vision-capable models can process images in tool results and user messages.
200→/// When true, the runner sends images as multimodal content blocks rather than
201→/// stripping them from the context.
202→///
203→/// Uses a deny-list approach: most modern LLMs support vision, so unknown
204→/// models default to `true`. The consequence of a false positive (sending
205→/// images to a text-only model) is an API error — visible and diagnosable.
206→/// The consequence of a false negative (stripping images from a capable model)
207→/// is a silent failure that confuses users.
208→pub fn supports_vision_for_model(model_id: &str) -> bool {
209→    let id = capability_model_id(model_id);
210→
211→    // ── Known text-only models ──────────────────────────────────────
212→    // Code-focused models
213→    if id.starts_with("codestral") {
214→        return false;
215→    }
216→    // Legacy OpenAI models without vision
217→    if id.starts_with("gpt-3.5") || id.starts_with("text-") || id.starts_with("gpt-4-") {
218→        // gpt-4-turbo and gpt-4-vision variants support vision
219→        if id.starts_with("gpt-4-turbo") || id.starts_with("gpt-4-vision") {
220→            return true;
221→        }
222→        return false;
223→    }
224→    // Z.AI GLM text-only models (vision variants contain 'v' suffix)
225→    if id.starts_with("glm-") && !id.contains('v') {
226→        return false;
227→    }
228→
229→    // ── Default: assume vision support ──────────────────────────────
230→    true
231→}
232→
233→/// Check if a model supports reasoning/extended thinking.
234→///
235→/// Reasoning-capable models can use the `reasoning_effort` configuration
236→/// to control the depth of extended thinking. This is used by the UI and
237→/// validation to inform users when reasoning_effort is set on a model
238→/// that doesn't support it.
239→pub fn supports_reasoning_for_model(model_id: &str) -> bool {
240→    let id = capability_model_id(model_id);
241→    // Anthropic Claude Opus 4.5+ and Sonnet 4.5+
242→    if id.starts_with("claude-opus-4-5")
243→        || id.starts_with("claude-sonnet-4-5")
244→        || id.starts_with("claude-opus-4-6")
245→        || id.starts_with("claude-sonnet-4-6")
246→    {
247→        return true;
248→    }
249→    // Claude 3.7 Sonnet supports extended thinking
250→    if id.starts_with("claude-3-7-sonnet") {
251→        return true;
252→    }
253→    // OpenAI o-series reasoning models
254→    if id.starts_with("o1") || id.starts_with("o3") || id.starts_with("o4") {
255→        return true;
256→    }
257→    // Gemini 2.5+ with thinking (2.5 Flash/Pro, 3 Flash, 3.1 Pro)
258→    if id.starts_with("gemini-2.5") || id.starts_with("gemini-3") {
259→        return true;
260→    }
261→    // OpenAI GPT-5.x models support reasoning_effort
262→    if id.starts_with("gpt-5") {
263→        return true;
264→    }
265→    // DeepSeek R1 / reasoning models
266→    if id.contains("deepseek-r1") || id.contains("deepseek-reasoner") {
267→        return true;
268→    }
269→    // xAI Grok 3+ reasoning models (Grok 3, Grok 3 Mini, Grok 4 series)
270→    if id.starts_with("grok-3") || id.starts_with("grok-4") {
271→        return true;
272→    }
273→    false
274→}
