  39→// ── Typed chat messages ─────────────────────────────────────────────────────
  40→
  41→/// Typed chat message for the LLM provider interface.
  42→///
  43→/// Only contains LLM-relevant fields — metadata like `created_at`, `model`,
  44→/// `provider`, `inputTokens`, `outputTokens` cannot exist here, so they
  45→/// can never leak into provider API requests.
  46→#[derive(Debug, Clone)]
  47→pub enum ChatMessage {
  48→    System {
  49→        content: String,
  50→    },
  51→    User {
  52→        content: UserContent,
  53→        /// Optional sender name for channel messages (Telegram, Discord, etc.).
  54→        name: Option<String>,
  55→    },
  56→    Assistant {
  57→        content: Option<String>,
  58→        tool_calls: Vec<ToolCall>,
  59→    },
  60→    Tool {
  61→        tool_call_id: String,
  62→        content: String,
  63→    },
  64→}
  65→
  66→/// User message content: plain text or multimodal (text + images).
  67→#[derive(Debug, Clone)]
  68→pub enum UserContent {
  69→    Text(String),
  70→    Multimodal(Vec<ContentPart>),
  71→}
  72→
  73→impl UserContent {
  74→    /// Create a text-only user content.
  75→    pub fn text(s: impl Into<String>) -> Self {
  76→        Self::Text(s.into())
  77→    }
  78→}
  79→
  80→/// A single part of a multimodal content array.
  81→#[derive(Debug, Clone)]
  82→pub enum ContentPart {
  83→    Text(String),
  84→    Image { media_type: String, data: String },
  85→}
  86→
  87→impl ChatMessage {
  88→    /// Create a system message.
  89→    pub fn system(content: impl Into<String>) -> Self {
  90→        Self::System {
  91→            content: content.into(),
  92→        }
  93→    }
  94→
  95→    /// Create a user message with plain text.
  96→    pub fn user(content: impl Into<String>) -> Self {
  97→        Self::User {
  98→            content: UserContent::Text(content.into()),
  99→            name: None,
 100→        }
 101→    }
 102→
 103→    /// Create a user message with plain text and a sender name.
 104→    pub fn user_named(content: impl Into<String>, name: impl Into<String>) -> Self {
 105→        Self::User {
 106→            content: UserContent::Text(content.into()),
 107→            name: Some(name.into()),
 108→        }
 109→    }
 110→
 111→    /// Create a user message with multimodal content.
 112→    pub fn user_multimodal(parts: Vec<ContentPart>) -> Self {
 113→        Self::User {
 114→            content: UserContent::Multimodal(parts),
 115→            name: None,
 116→        }
 117→    }
 118→
 119→    /// Create a user message with multimodal content and a sender name.
 120→    pub fn user_multimodal_named(parts: Vec<ContentPart>, name: impl Into<String>) -> Self {
 121→        Self::User {
 122→            content: UserContent::Multimodal(parts),
 123→            name: Some(name.into()),
 124→        }
 125→    }
 126→
 127→    /// Create an assistant message with text only (no tool calls).
 128→    pub fn assistant(content: impl Into<String>) -> Self {
 129→        Self::Assistant {
 130→            content: Some(content.into()),
 131→            tool_calls: vec![],
 132→        }
 133→    }
 134→
 135→    /// Create an assistant message with tool calls (and optional text).
 136→    pub fn assistant_with_tools(content: Option<String>, tool_calls: Vec<ToolCall>) -> Self {
 137→        Self::Assistant {
 138→            content,
 139→            tool_calls,
 140→        }
 141→    }
 142→
 143→    /// Create a tool result message.
 144→    pub fn tool(tool_call_id: impl Into<String>, content: impl Into<String>) -> Self {
 145→        Self::Tool {
 146→            tool_call_id: tool_call_id.into(),
 147→            content: content.into(),
 148→        }
 149→    }
 150→
 151→    /// Convert to OpenAI-compatible JSON format.
 152→    ///
 153→    /// Used by providers that speak the OpenAI Chat Completions API:
 154→    /// OpenAI, Mistral, Copilot, Kimi, Cerebras, etc.
 155→    #[must_use]
 156→    pub fn to_openai_value(&self) -> serde_json::Value {
 157→        match self {
 158→            ChatMessage::System { content } => {
 159→                serde_json::json!({ "role": "system", "content": content })
 160→            },
 161→            ChatMessage::User { content, name } => {
 162→                let mut msg = match content {
 163→                    UserContent::Text(text) => {
 164→                        serde_json::json!({ "role": "user", "content": text })
 165→                    },
 166→                    UserContent::Multimodal(parts) => {
 167→                        let blocks: Vec<serde_json::Value> = parts
 168→                            .iter()
 169→                            .map(|part| match part {
 170→                                ContentPart::Text(text) => {
 171→                                    serde_json::json!({ "type": "text", "text": text })
 172→                                },
 173→                                ContentPart::Image { media_type, data } => {
 174→                                    let data_uri = format!("data:{media_type};base64,{data}");
 175→                                    serde_json::json!({
 176→                                        "type": "image_url",
 177→                                        "image_url": { "url": data_uri }
 178→                                    })
 179→                                },
 180→                            })
 181→                            .collect();
 182→                        serde_json::json!({ "role": "user", "content": blocks })
 183→                    },
 184→                };
 185→                if let Some(n) = name {
 186→                    msg["name"] = serde_json::Value::String(n.clone());
 187→                }
 188→                msg
 189→            },
 190→            ChatMessage::Assistant {
 191→                content,
 192→                tool_calls,
 193→            } => {
 194→                if tool_calls.is_empty() {
 195→                    serde_json::json!({
 196→                        "role": "assistant",
 197→                        "content": content.as_deref().unwrap_or(""),
 198→                    })
 199→                } else {
 200→                    let tc_json: Vec<serde_json::Value> = tool_calls
 201→                        .iter()
 202→                        .map(|tc| {
 203→                            serde_json::json!({
 204→                                "id": tc.id,
 205→                                "type": "function",
 206→                                "function": {
 207→                                    "name": tc.name,
 208→                                    "arguments": tc.arguments.to_string(),
 209→                                }
 210→                            })
 211→                        })
 212→                        .collect();
 213→                    let mut msg = serde_json::json!({
 214→                        "role": "assistant",
 215→                        "tool_calls": tc_json,
 216→                    });
 217→                    if let Some(text) = content {
 218→                        msg["content"] = serde_json::Value::String(text.clone());
 219→                    }
 220→                    msg
 221→                }
 222→            },
 223→            ChatMessage::Tool {
 224→                tool_call_id,
 225→                content,
 226→            } => {
 227→                serde_json::json!({
 228→                    "role": "tool",
 229→                    "tool_call_id": tool_call_id,
 230→                    "content": content,
 231→                })
 232→            },
 233→        }
 234→    }
 235→}
 236→
 237→/// Convert persisted JSON messages (from session store) to typed `ChatMessage`s.
 238→///
 239→/// Skips messages that don't have a valid `role` field, logging a warning.
 240→/// Metadata fields (`created_at`, `model`, `provider`, `inputTokens`,
 241→/// `outputTokens`, `channel`) are silently dropped — they only exist in
 242→/// the persisted JSON, not in `ChatMessage`.
 243→pub fn values_to_chat_messages(values: &[serde_json::Value]) -> Vec<ChatMessage> {
 244→    let mut messages = Vec::with_capacity(values.len());
 245→    // Track tool_call IDs emitted by assistant messages so we only include
 246→    // tool/tool_result messages that have a matching assistant tool_call.
 247→    // Orphan tool results (e.g. from explicit /sh commands) would cause
 248→    // provider API errors.
 249→    let mut pending_tool_call_ids: std::collections::HashSet<String> =
 250→        std::collections::HashSet::new();
 251→    for (i, val) in values.iter().enumerate() {
 252→        let Some(role) = val["role"].as_str() else {
 253→            tracing::warn!(index = i, "skipping message with missing/invalid role");
 254→            continue;
 255→        };
 256→        match role {
 257→            "system" => {
 258→                let content = val["content"].as_str().unwrap_or("").to_string();
 259→                messages.push(ChatMessage::system(content));
 260→            },
 261→            "user" => {
 262→                // Extract sender name from persisted channel metadata.
 263→                let sender_name = val
 264→                    .get("channel")
 265→                    .and_then(|ch| {
 266→                        ch["sender_name"]
 267→                            .as_str()
 268→                            .or_else(|| ch["username"].as_str())
 269→                    })
 270→                    .map(|s| s.to_string());
 271→
 272→                let document_context = val["documents"].as_array().and_then(|documents| {
 273→                    let mut sections = Vec::new();
 274→                    for document in documents {
 275→                        let Some(display_name) = document["display_name"].as_str() else {
 276→                            continue;
 277→                        };
 278→                        let Some(mime_type) = document["mime_type"].as_str() else {
 279→                            continue;
 280→                        };
 281→                        let Some(media_ref) = document["media_ref"].as_str() else {
 282→                            continue;
 283→                        };
 284→                        let absolute_path = document_absolute_path_from_media_ref(media_ref);
 285→                        sections.push(format!(
 286→                            "filename: {display_name}\nmime_type: {mime_type}\nlocal_path: {absolute_path}\nmedia_ref: {media_ref}"
 287→                        ));
 288→                    }
 289→                    if sections.is_empty() {
 290→                        None
 291→                    } else {
 292→                        let mut rendered = vec!["[Inbound documents available]".to_string()];
 293→                        rendered.extend(sections);
 294→                        Some(rendered.join("\n\n"))
 295→                    }
 296→                });
 297→
 298→                // Content can be a string or an array (multimodal).
 299→                if let Some(text) = val["content"].as_str() {
 300→                    let content = if let Some(ref document_context) = document_context {
 301→                        if text.trim().is_empty() {
 302→                            document_context.clone()
 303→                        } else {
 304→                            format!("{text}\n\n{document_context}")
 305→                        }
 306→                    } else {
 307→                        text.to_string()
 308→                    };
 309→                    messages.push(ChatMessage::User {
 310→                        content: UserContent::Text(content),
 311→                        name: sender_name,
 312→                    });
 313→                } else if let Some(arr) = val["content"].as_array() {
 314→                    let mut parts: Vec<ContentPart> = arr
 315→                        .iter()
 316→                        .filter_map(|block| {
 317→                            let block_type = block["type"].as_str()?;
 318→                            match block_type {
 319→                                "text" => {
 320→                                    let text = block["text"].as_str()?.to_string();
 321→                                    Some(ContentPart::Text(text))
 322→                                },
 323→                                "image_url" => {
 324→                                    let url = block["image_url"]["url"].as_str()?;
 325→                                    let (media_type, data) = parse_data_uri(url)?;
 326→                                    Some(ContentPart::Image {
 327→                                        media_type: media_type.to_string(),
 328→                                        data: data.to_string(),
 329→                                    })
 330→                                },
 331→                                _ => None,
 332→                            }
 333→                        })
 334→                        .collect();
 335→                    if let Some(document_context) = document_context {
 336→                        if let Some(ContentPart::Text(text)) = parts
 337→                            .iter_mut()
 338→                            .find(|part| matches!(part, ContentPart::Text(_)))
 339→                        {
 340→                            if !text.trim().is_empty() {
 341→                                text.push_str("\n\n");
 342→                            }
 343→                            text.push_str(&document_context);
 344→                        } else {
 345→                            parts.insert(0, ContentPart::Text(document_context));
 346→                        }
 347→                    }
 348→                    messages.push(ChatMessage::User {
 349→                        content: UserContent::Multimodal(parts),
 350→                        name: sender_name,
 351→                    });
 352→                } else {
 353→                    messages.push(ChatMessage::User {
 354→                        content: UserContent::Text(document_context.unwrap_or_default()),
 355→                        name: sender_name,
 356→                    });
 357→                }
 358→            },
 359→            "assistant" => {
 360→                let content = val["content"].as_str().map(|s| s.to_string());
 361→                let tool_calls: Vec<ToolCall> = val["tool_calls"]
 362→                    .as_array()
 363→                    .map(|tcs| {
 364→                        tcs.iter()
 365→                            .filter_map(|tc| {
 366→                                let id = tc["id"].as_str()?.to_string();
 367→                                let name = tc["function"]["name"].as_str()?.to_string();
 368→                                let arguments =
 369→                                    decode_tool_call_arguments(tc["function"].get("arguments"));
 370→                                Some(ToolCall {
 371→                                    id,
 372→                                    name,
 373→                                    arguments,
 374→                                })
 375→                            })
 376→                            .collect()
 377→                    })
 378→                    .unwrap_or_default();
 379→                for tc in &tool_calls {
 380→                    pending_tool_call_ids.insert(tc.id.clone());
 381→                }
 382→                messages.push(ChatMessage::Assistant {
 383→                    content,
 384→                    tool_calls,
 385→                });
 386→            },
 387→            "tool" => {
 388→                let tool_call_id = val["tool_call_id"].as_str().unwrap_or("").to_string();
 389→                if !pending_tool_call_ids.remove(&tool_call_id) {
 390→                    tracing::debug!(tool_call_id, "skipping orphan tool message");
 391→                    continue;
 392→                }
 393→                let content = if let Some(s) = val["content"].as_str() {
 394→                    s.to_string()
 395→                } else {
 396→                    val["content"].to_string()
 397→                };
 398→                messages.push(ChatMessage::tool(tool_call_id, content));
 399→            },
 400→            // tool_result entries are persisted tool execution output; convert
 401→            // them to standard tool messages so the LLM sees its own results.
 402→            "tool_result" => {
 403→                let tool_call_id = val["tool_call_id"].as_str().unwrap_or("").to_string();
 404→                if !pending_tool_call_ids.remove(&tool_call_id) {
 405→                    tracing::debug!(tool_call_id, "skipping orphan tool_result message");
 406→                    continue;
 407→                }
 408→                let content = if let Some(err) = val["error"].as_str() {
 409→                    format!("Error: {err}")
 410→                } else if let Some(result) = val.get("result") {
 411→                    if let Some(s) = result.as_str() {
 412→                        s.to_string()
 413→                    } else {
 414→                        result.to_string()
 415→                    }
 416→                } else {
 417→                    String::new()
 418→                };
 419→                messages.push(ChatMessage::tool(tool_call_id, content));
 420→            },
 421→            // notice entries are UI-only informational messages.
 422→            "notice" => continue,
 423→            other => {
 424→                tracing::warn!(
 425→                    index = i,
 426→                    role = other,
 427→                    "skipping message with unknown role"
 428→                );
 429→            },
 430→        }
 431→    }
 432→    messages
 433→}
