 435→// ── Stream events ───────────────────────────────────────────────────────────
 436→
 437→/// Events emitted during streaming LLM completion.
 438→#[derive(Debug, Clone)]
 439→pub enum StreamEvent {
 440→    /// Text content delta.
 441→    Delta(String),
 442→    /// Raw provider event payload (for debugging API responses).
 443→    ProviderRaw(serde_json::Value),
 444→    /// Reasoning/planning text delta (not user-visible final answer text).
 445→    ReasoningDelta(String),
 446→    /// A tool call has started (content_block_start with tool_use).
 447→    ToolCallStart {
 448→        /// Tool call ID from the provider.
 449→        id: String,
 450→        /// Tool name being called.
 451→        name: String,
 452→        /// Index of this tool call in the response (0-based).
 453→        index: usize,
 454→    },
 455→    /// Streaming delta for tool call arguments (JSON fragment).
 456→    ToolCallArgumentsDelta {
 457→        /// Index of the tool call this delta belongs to.
 458→        index: usize,
 459→        /// JSON fragment to append to the arguments.
 460→        delta: String,
 461→    },
 462→    /// A tool call's arguments are complete.
 463→    ToolCallComplete {
 464→        /// Index of the completed tool call.
 465→        index: usize,
 466→    },
 467→    /// Stream completed successfully.
 468→    Done(Usage),
 469→    /// An error occurred.
 470→    Error(String),
 471→}
 472→
 473→/// LLM provider trait (Anthropic, OpenAI, Google, etc.).
 474→#[async_trait]
 475→pub trait LlmProvider: Send + Sync {
 476→    fn name(&self) -> &str;
 477→
 478→    /// Model identifier (e.g. "claude-sonnet-4-20250514", "gpt-4o").
 479→    fn id(&self) -> &str;
 480→
 481→    async fn complete(
 482→        &self,
 483→        messages: &[ChatMessage],
 484→        tools: &[serde_json::Value],
 485→    ) -> anyhow::Result<CompletionResponse>;
 486→
 487→    /// Whether this provider supports tool/function calling.
 488→    /// Defaults to false; providers that handle the `tools` parameter
 489→    /// in `complete()` should override this to return true.
 490→    fn supports_tools(&self) -> bool {
 491→        false
 492→    }
 493→
 494→    /// Context window size in tokens for this model.
 495→    /// Used to detect when conversation approaches the limit and trigger auto-compact.
 496→    fn context_window(&self) -> u32 {
 497→        200_000
 498→    }
 499→
 500→    /// Whether this provider supports vision (image inputs).
 501→    /// When true, tool results containing images will be sent as multimodal
 502→    /// content blocks instead of stripping the image data.
 503→    fn supports_vision(&self) -> bool {
 504→        false
 505→    }
 506→
 507→    /// Configured tool mode for this provider, if any.
 508→    ///
 509→    /// Returns `None` when the provider has no explicit tool mode override
 510→    /// (the caller should fall back to `Auto` behavior based on `supports_tools()`).
 511→    fn tool_mode(&self) -> Option<moltis_config::ToolMode> {
 512→        None
 513→    }
 514→
 515→    /// Stream a completion, yielding delta/done/error events.
 516→    fn stream(
 517→        &self,
 518→        messages: Vec<ChatMessage>,
 519→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>>;
 520→
 521→    /// Stream a completion with tool support.
 522→    ///
 523→    /// Like `stream()`, but accepts tool schemas and can emit `ToolCallStart`,
 524→    /// `ToolCallArgumentsDelta`, and `ToolCallComplete` events in addition to
 525→    /// text deltas.
 526→    ///
 527→    /// Default implementation falls back to `stream()` (ignoring tools).
 528→    /// Providers with native streaming tool support should override this.
 529→    fn stream_with_tools(
 530→        &self,
 531→        messages: Vec<ChatMessage>,
 532→        _tools: Vec<serde_json::Value>,
 533→    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
 534→        self.stream(messages)
 535→    }
 536→
 537→    /// Configured reasoning effort for this provider instance, if any.
 538→    ///
 539→    /// Providers that support extended thinking (Anthropic, OpenAI o-series)
 540→    /// use this value when building API requests.
 541→    fn reasoning_effort(&self) -> Option<ReasoningEffort> {
 542→        None
 543→    }
 544→
 545→    /// Return a new provider with reasoning effort set, if supported.
 546→    ///
 547→    /// Returns `None` for providers that don't support reasoning effort.
 548→    /// Used by sub-agent spawning to apply per-agent reasoning settings
 549→    /// without mutating the shared registry provider.
 550→    fn with_reasoning_effort(
 551→        self: Arc<Self>,
 552→        _effort: ReasoningEffort,
 553→    ) -> Option<Arc<dyn LlmProvider>> {
 554→        None
 555→    }
 556→
 557→    /// Send the cheapest request available that proves the model can answer.
 558→    ///
 559→    /// The default implementation streams a tiny prompt and returns as soon as
 560→    /// the first text delta or terminal event arrives. Providers can override
 561→    /// this to use provider-specific low-cost probe requests.
 562→    async fn probe(&self) -> anyhow::Result<()> {
 563→        let probe = vec![ChatMessage::user("ping")];
 564→        let mut stream = self.stream(probe);
 565→
 566→        let result = tokio::time::timeout(Duration::from_secs(30), async {
 567→            while let Some(event) = stream.next().await {
 568→                match event {
 569→                    StreamEvent::Delta(_) | StreamEvent::Done(_) => return Ok(()),
 570→                    StreamEvent::Error(err) => return Err(anyhow::anyhow!(err)),
 571→                    _ => continue,
 572→                }
 573→            }
 574→            Err(anyhow::anyhow!("stream ended without producing any output"))
 575→        })
 576→        .await;
 577→
 578→        drop(stream);
 579→
 580→        match result {
 581→            Ok(inner) => inner,
 582→            Err(_) => Err(anyhow::anyhow!("Connection timed out after 30 seconds")),
 583→        }
 584→    }
 585→
 586→    /// Fetch runtime model metadata from the provider API.
 587→    ///
 588→    /// The default implementation returns a `ModelMetadata` derived from the
 589→    /// static `context_window()` value. Providers that support a `/models`
 590→    /// endpoint can override this to fetch the actual context length at runtime.
 591→    async fn model_metadata(&self) -> anyhow::Result<ModelMetadata> {
 592→        Ok(ModelMetadata {
 593→            id: self.id().to_string(),
 594→            context_length: self.context_window(),
 595→        })
 596→    }
 597→}
