 599→/// Response from an LLM completion call.
 600→#[derive(Debug)]
 601→pub struct CompletionResponse {
 602→    pub text: Option<String>,
 603→    pub tool_calls: Vec<ToolCall>,
 604→    pub usage: Usage,
 605→}
 606→
 607→pub const MAX_CAPTURED_PROVIDER_RAW_EVENTS: usize = 256;
 608→
 609→#[derive(Debug, Clone)]
 610→pub struct ToolCall {
 611→    pub id: String,
 612→    pub name: String,
 613→    pub arguments: serde_json::Value,
 614→}
 615→
 616→#[derive(Debug, Clone, Default)]
 617→pub struct Usage {
 618→    pub input_tokens: u32,
 619→    pub output_tokens: u32,
 620→    pub cache_read_tokens: u32,
 621→    pub cache_write_tokens: u32,
 622→}
 623→
 624→impl Usage {
 625→    #[must_use]
 626→    pub fn saturating_add(&self, other: &Self) -> Self {
 627→        Self {
 628→            input_tokens: self.input_tokens.saturating_add(other.input_tokens),
 629→            output_tokens: self.output_tokens.saturating_add(other.output_tokens),
 630→            cache_read_tokens: self
 631→                .cache_read_tokens
 632→                .saturating_add(other.cache_read_tokens),
 633→            cache_write_tokens: self
 634→                .cache_write_tokens
 635→                .saturating_add(other.cache_write_tokens),
 636→        }
 637→    }
 638→
 639→    pub fn saturating_add_assign(&mut self, other: &Self) {
 640→        *self = self.saturating_add(other);
 641→    }
 642→}
 643→
 644→pub fn push_capped_provider_raw_event(
 645→    raw_events: &mut Vec<serde_json::Value>,
 646→    raw_event: serde_json::Value,
 647→) {
 648→    if raw_events.len() < MAX_CAPTURED_PROVIDER_RAW_EVENTS {
 649→        raw_events.push(raw_event);
 650→    }
 651→}
