1068→            serde_json::json!({"role": "assistant", "content": "real response"}),
1069→        ];
1070→        let msgs = values_to_chat_messages(&values);
1071→        assert_eq!(msgs.len(), 2, "should produce exactly 2 messages, not more");
1072→        // First message must be User containing the full injected text.
