 59→/// IANA timezone (e.g. `"Europe/Paris"`).
 60→///
 61→/// Wraps [`chrono_tz::Tz`] and (de)serialises as a plain string so it stays
 62→/// compatible with the YAML frontmatter in `USER.md`.
 63→#[derive(Debug, Clone)]
 64→pub struct Timezone(pub chrono_tz::Tz);
 65→
 66→#[derive(Debug, thiserror::Error)]
 67→#[error("unknown IANA timezone: {value}")]
 68→pub struct TimezoneParseError {
 69→    value: String,
 70→}
 71→
 72→impl Timezone {
 73→    /// The IANA name, e.g. `"Europe/Paris"`.
 74→    #[must_use]
 75→    pub fn name(&self) -> &str {
 76→        self.0.name()
 77→    }
 78→
 79→    /// The inner [`chrono_tz::Tz`] value.
 80→    #[must_use]
 81→    pub fn tz(&self) -> chrono_tz::Tz {
 82→        self.0
 83→    }
 84→}
 85→
 86→impl std::fmt::Display for Timezone {
 87→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 88→        f.write_str(self.0.name())
 89→    }
 90→}
 91→
 92→impl std::str::FromStr for Timezone {
 93→    type Err = TimezoneParseError;
 94→
 95→    fn from_str(s: &str) -> Result<Self, Self::Err> {
 96→        s.parse::<chrono_tz::Tz>()
 97→            .map(Self)
 98→            .map_err(|_| TimezoneParseError {
 99→                value: s.to_string(),
100→            })
101→    }
102→}
103→
104→impl From<chrono_tz::Tz> for Timezone {
105→    fn from(tz: chrono_tz::Tz) -> Self {
106→        Self(tz)
107→    }
108→}
109→
110→impl Serialize for Timezone {
111→    fn serialize<S: serde::Serializer>(&self, serializer: S) -> Result<S::Ok, S::Error> {
112→        serializer.serialize_str(self.0.name())
113→    }
114→}
115→
116→impl<'de> Deserialize<'de> for Timezone {
117→    fn deserialize<D: Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
118→        let s = String::deserialize(deserializer)?;
119→        s.parse::<Self>().map_err(serde::de::Error::custom)
120→    }
121→}
