  1→//! Model ID manipulation: namespacing, reasoning suffix parsing, raw ID extraction.
  2→
  3→/// Separator between provider namespace and model ID.
  4→pub(crate) const MODEL_ID_NAMESPACE_SEP: &str = "::";
  5→
  6→/// Separator between a model ID and its reasoning effort suffix.
  7→pub(crate) const REASONING_SUFFIX_SEP: char = '@';
  8→
  9→/// Reasoning effort suffixes appended to model IDs.
 10→pub(crate) const REASONING_SUFFIXES: &[(&str, moltis_agents::model::ReasoningEffort)] = &[
 11→    ("reasoning-low", moltis_agents::model::ReasoningEffort::Low),
 12→    (
 13→        "reasoning-medium",
 14→        moltis_agents::model::ReasoningEffort::Medium,
 15→    ),
 16→    (
 17→        "reasoning-high",
 18→        moltis_agents::model::ReasoningEffort::High,
 19→    ),
 20→];
 21→
 22→#[must_use]
 23→pub fn namespaced_model_id(provider: &str, model_id: &str) -> String {
 24→    if model_id.contains(MODEL_ID_NAMESPACE_SEP) {
 25→        return model_id.to_string();
 26→    }
 27→    format!("{provider}{MODEL_ID_NAMESPACE_SEP}{model_id}")
 28→}
 29→
 30→/// Split a model ID into (base_id, optional reasoning effort).
 31→///
 32→/// Examples:
 33→/// - `"anthropic::claude-opus-4-5@reasoning-high"` → `("anthropic::claude-opus-4-5", Some(High))`
 34→/// - `"gpt-4o"` → `("gpt-4o", None)`
 35→#[must_use]
 36→pub fn split_reasoning_suffix(
 37→    model_id: &str,
 38→) -> (&str, Option<moltis_agents::model::ReasoningEffort>) {
 39→    if let Some((base, suffix)) = model_id.rsplit_once(REASONING_SUFFIX_SEP) {
 40→        for &(tag, effort) in REASONING_SUFFIXES {
 41→            if suffix == tag {
 42→                return (base, Some(effort));
 43→            }
 44→        }
 45→    }
 46→    (model_id, None)
 47→}
 48→
 49→#[must_use]
 50→pub fn raw_model_id(model_id: &str) -> &str {
 51→    // Fast path: skip reasoning suffix parsing when no `@` is present.
 52→    let base = if model_id.contains(REASONING_SUFFIX_SEP) {
 53→        split_reasoning_suffix(model_id).0
 54→    } else {
 55→        model_id
 56→    };
 57→    base.rsplit_once(MODEL_ID_NAMESPACE_SEP)
 58→        .map(|(_, raw)| raw)
 59→        .unwrap_or(base)
 60→}
 61→
 62→#[must_use]
 63→pub(crate) fn capability_model_id(model_id: &str) -> &str {
 64→    let raw = raw_model_id(model_id).trim();
 65→    raw.rsplit('/')
 66→        .next()
 67→        .filter(|id| !id.is_empty())
 68→        .unwrap_or(raw)
 69→}
 70→
 71→pub(crate) fn configured_model_for_provider(model_id: &str) -> &str {
 72→    raw_model_id(model_id)
 73→}
