  1→//! Model capability heuristics: context window, tool support, vision, reasoning.
  2→
  3→use {crate::model_id::capability_model_id, moltis_config::schema::ModelOverride};
  4→
  5→/// Extract a `HashMap<String, u32>` of model ID → context window from
  6→/// a `HashMap<String, ModelOverride>`, filtering out entries without a
  7→/// `context_window` value.
  8→#[must_use]
  9→pub fn extract_cw_overrides(
 10→    overrides: &std::collections::HashMap<String, ModelOverride>,
 11→) -> std::collections::HashMap<String, u32> {
 12→    overrides
 13→        .iter()
 14→        .filter_map(|(k, v)| v.context_window.map(|cw| (k.clone(), cw)))
 15→        .collect()
 16→}
 17→
 18→/// Return the known context window size (in tokens) for a model ID.
 19→/// Falls back to 200,000 for unknown models.
 20→#[must_use]
 21→pub fn context_window_for_model(model_id: &str) -> u32 {
 22→    context_window_for_model_inner(model_id)
 23→}
 24→
 25→/// Return the context window size for a model ID, respecting config overrides.
 26→///
 27→/// Precedence (highest to lowest):
 28→/// 1. Provider-scoped config override (`provider_overrides[model_id].context_window`)
 29→/// 2. Global config override (`global_overrides[model_id].context_window`)
 30→/// 3. Hardcoded heuristic ([`context_window_for_model_inner`])
 31→///
 32→/// Both override maps use the **normalized** model ID (after
 33→/// [`capability_model_id`] processing) as the lookup key.
 34→///
 35→/// Note: This function accepts `HashMap<String, u32>` (not the config crate's
 36→/// `ModelOverride`) to keep the providers crate independent of the config crate.
 37→/// Callers are responsible for extracting the `u32` from `ModelOverride.context_window`.
 38→///
 39→/// When no config is provided, this is equivalent to [`context_window_for_model`].
 40→#[must_use]
 41→pub fn context_window_for_model_with_config(
 42→    model_id: &str,
 43→    global_overrides: &std::collections::HashMap<String, u32>,
 44→    provider_overrides: &std::collections::HashMap<String, u32>,
 45→) -> u32 {
 46→    let normalized = capability_model_id(model_id);
 47→
 48→    // 1. Provider-scoped override (highest precedence)
 49→    if let Some(&cw) = provider_overrides.get(normalized) {
 50→        return cw;
 51→    }
 52→    // 2. Global override
 53→    if let Some(&cw) = global_overrides.get(normalized) {
 54→        return cw;
 55→    }
 56→    // 3. Hardcoded heuristic
 57→    context_window_for_model_inner(model_id)
 58→}
 59→
 60→/// Inner heuristic — kept private so callers go through the public wrappers.
 61→fn context_window_for_model_inner(model_id: &str) -> u32 {
 62→    let model_id = capability_model_id(model_id);
 63→    // Codestral has the largest window at 256k.
 64→    if model_id.starts_with("codestral") {
 65→        return 256_000;
 66→    }
 67→    // Claude models: 200k.
 68→    if model_id.starts_with("claude-") {
 69→        return 200_000;
 70→    }
 71→    // OpenAI o3/o4-mini: 200k.
 72→    if model_id.starts_with("o3") || model_id.starts_with("o4-mini") {
 73→        return 200_000;
 74→    }
 75→    // GPT-4o, GPT-4-turbo, GPT-5 series: 128k.
 76→    if model_id.starts_with("gpt-4") || model_id.starts_with("gpt-5") {
 77→        return 128_000;
 78→    }
 79→    // Mistral Large: 128k.
 80→    if model_id.starts_with("mistral-large") {
 81→        return 128_000;
 82→    }
 83→    // Gemini: 1M context.
 84→    if model_id.starts_with("gemini-") {
 85→        return 1_000_000;
 86→    }
 87→    // Kimi K2.5: 128k.
 88→    if model_id.starts_with("kimi-") {
 89→        return 128_000;
 90→    }
 91→    // MiniMax M2/M2.1/M2.5/M2.7: 204,800.
 92→    if model_id.starts_with("MiniMax-") {
 93→        return 204_800;
 94→    }
 95→    // Z.AI GLM-4-32B: 128k.
 96→    if model_id == "glm-4-32b-0414-128k" {
 97→        return 128_000;
 98→    }
 99→    // Z.AI GLM-5/4.7/4.6/4.5 series: 128k.
100→    if model_id.starts_with("glm-") {
101→        return 128_000;
102→    }
103→    // Qwen3 series (Qwen3, Qwen3-Coder): 128k.
104→    if model_id.starts_with("qwen3") {
105→        return 128_000;
106→    }
107→    // Default fallback.
108→    200_000
109→}
