276→/// Capabilities that a model is known to support.
277→///
278→/// Populated at registration time from the pattern-matching heuristics.
279→/// Carried on `ModelInfo` so downstream code can check capabilities
280→/// without a provider instance or re-running the heuristic.
281→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, serde::Serialize)]
282→pub struct ModelCapabilities {
283→    /// Supports OpenAI-style function/tool calling.
284→    pub tools: bool,
285→    /// Supports image/vision inputs.
286→    pub vision: bool,
287→    /// Supports extended thinking / reasoning effort.
288→    pub reasoning: bool,
289→}
290→
291→impl ModelCapabilities {
292→    /// Infer capabilities from the model ID using the pattern-matching heuristics.
293→    #[must_use]
294→    pub fn infer(model_id: &str) -> Self {
295→        Self {
296→            tools: supports_tools_for_model(model_id),
297→            vision: supports_vision_for_model(model_id),
298→            reasoning: supports_reasoning_for_model(model_id),
299→        }
300→    }
301→}
302→
303→/// Info about an available model.
304→#[derive(Debug, Clone, serde::Serialize)]
305→pub struct ModelInfo {
306→    pub id: String,
307→    pub provider: String,
308→    pub display_name: String,
309→    /// Unix timestamp from the provider API (e.g. OpenAI `created` field).
310→    /// `None` for static catalog entries.
311→    pub created_at: Option<i64>,
312→    /// Flagged by the provider as a recommended/flagship model.
313→    pub recommended: bool,
314→    /// Model capabilities, resolved at registration time.
315→    pub capabilities: ModelCapabilities,
316→}
