 66→function buildModelItem(m, currentId) {
 67→	var el = document.createElement("div");
 68→	el.className = "model-dropdown-item";
 69→	if (m.id === currentId) el.classList.add("selected");
 70→	if (m.unsupported) el.classList.add("model-dropdown-item-unsupported");
 71→
 72→	var label = document.createElement("span");
 73→	label.className = "model-item-label";
 74→	label.textContent = m.displayName || m.id;
 75→	el.appendChild(label);
 76→
 77→	var meta = document.createElement("span");
 78→	meta.className = "model-item-meta";
 79→
 80→	if (m.provider) {
 81→		var prov = document.createElement("span");
 82→		prov.className = "model-item-provider";
 83→		prov.textContent = m.provider;
 84→		meta.appendChild(prov);
 85→	}
 86→
 87→	if (m.unsupported) {
 88→		var badge = document.createElement("span");
 89→		badge.className = "model-item-unsupported";
 90→		badge.textContent = t("common:labels.unsupported");
 91→		if (m.unsupportedReason) badge.title = m.unsupportedReason;
 92→		meta.appendChild(badge);
 93→	}
