 1→// ── Server-injected data (gon pattern) ────────────────────
 2→//
 3→// The server injects `window.__MOLTIS__ = { ... }` into every
 4→// page <head> before any module script runs.  This module
 5→// provides typed access, runtime updates, and a refresh
 6→// mechanism that re-fetches the data from `/api/gon`.
 7→//
 8→// Register listeners with `onChange(key, fn)` to react when
 9→// a key is updated (via `set()` or `refresh()`).
10→
11→var gon = window.__MOLTIS__ || {};
12→var listeners = {};
13→
14→export function get(key) {
15→	return gon[key] ?? null;
16→}
17→
18→export function set(key, value) {
19→	gon[key] = value;
20→	notify(key, value);
21→}
22→
23→export function onChange(key, fn) {
24→	if (!listeners[key]) listeners[key] = [];
25→	listeners[key].push(fn);
26→}
27→
28→export function offChange(key, fn) {
29→	var arr = listeners[key];
30→	if (!arr) return;
31→	var idx = arr.indexOf(fn);
32→	if (idx !== -1) arr.splice(idx, 1);
33→}
34→
35→export function refresh() {
36→	return fetch(`/api/gon?_=${Date.now()}`, {
37→		cache: "no-store",
38→		headers: {
39→			"Cache-Control": "no-cache",
40→			Pragma: "no-cache",
41→		},
42→	})
43→		.then((r) => (r.ok ? r.json() : null))
44→		.then((data) => {
45→			if (!data) return;
46→			for (var key of Object.keys(data)) {
47→				gon[key] = data[key];
48→				notify(key, data[key]);
49→			}
50→		});
51→}
52→
53→function notify(key, value) {
54→	for (var fn of listeners[key] || []) fn(value);
55→}
56→

