 102→/// Memory snapshot included in gon data and tick broadcasts.
 103→#[derive(serde::Serialize)]
 104→#[serde(rename_all = "camelCase")]
 105→pub(crate) struct MemSnapshot {
 106→    process: u64,
 107→    #[serde(skip_serializing_if = "Option::is_none")]
 108→    local_llama_cpp: Option<u64>,
 109→    available: u64,
 110→    total: u64,
 111→}
 112→
 113→/// Collect a point-in-time memory snapshot (process RSS + local llama.cpp +
 114→/// system memory).
 115→pub(crate) fn collect_mem_snapshot() -> MemSnapshot {
 116→    let mut sys = sysinfo::System::new();
 117→    sys.refresh_memory();
 118→    let pid = sysinfo::get_current_pid().ok();
 119→    if let Some(pid) = pid {
 120→        sys.refresh_processes_specifics(
 121→            sysinfo::ProcessesToUpdate::Some(&[pid]),
 122→            false,
 123→            sysinfo::ProcessRefreshKind::nothing().with_memory(),
 124→        );
 125→    }
 126→    let process = pid
 127→        .and_then(|p| sys.process(p))
 128→        .map(|p| p.memory())
 129→        .unwrap_or(0);
 130→    let local_llama_cpp = moltis_gateway::server::local_llama_cpp_bytes_for_ui();
 131→    let total = sys.total_memory();
 132→    // available_memory() returns 0 on macOS; fall back to total − used.
 133→    let available = match sys.available_memory() {
 134→        0 => total.saturating_sub(sys.used_memory()),
 135→        v => v,
 136→    };
 137→    MemSnapshot {
 138→        process,
 139→        local_llama_cpp: (local_llama_cpp > 0).then_some(local_llama_cpp),
 140→        available,
 141→        total,
 142→    }
 143→}
