 146→
 147→fn detect_git_branch() -> Option<String> {
 148→    static BRANCH: std::sync::OnceLock<Option<String>> = std::sync::OnceLock::new();
 149→    BRANCH
 150→        .get_or_init(|| {
 151→            let repo = gix::discover(".").ok()?;
 152→            let head = repo.head().ok()?;
 153→            let branch = head.referent_name()?.shorten().to_string();
 154→            parse_git_branch(&branch)
 155→        })
 156→        .clone()
 157→}
 158→
 159→fn parse_git_branch(raw: &str) -> Option<String> {
 160→    let branch = raw.trim();
 161→    if branch.is_empty() || branch == "main" || branch == "master" {
 162→        None
 163→    } else {
 164→        Some(branch.to_owned())
 165→    }
 166→}
