 168→const SESSION_PREVIEW_MAX_CHARS: usize = 200;
 169→
 170→fn truncate_preview(text: &str, max_chars: usize) -> String {
 171→    let mut chars = text.chars();
 172→    let mut out = String::new();
 173→    for _ in 0..max_chars {
 174→        if let Some(ch) = chars.next() {
 175→            out.push(ch);
 176→        } else {
 177→            return out;
 178→        }
 179→    }
 180→    if chars.next().is_some() {
 181→        out.push('…');
 182→    }
 183→    out
 184→}
