 186→fn default_channel_session_key(target: &moltis_channels::ChannelReplyTarget) -> String {
 187→    match &target.thread_id {
 188→        Some(thread_id) => format!(
 189→            "{}:{}:{}:{}",
 190→            target.channel_type, target.account_id, target.chat_id, thread_id
 191→        ),
 192→        None => format!(
 193→            "{}:{}:{}",
 194→            target.channel_type, target.account_id, target.chat_id
 195→        ),
 196→    }
 197→}
