 199→async fn build_recent_sessions_snapshot(gw: &GatewayState, limit: usize) -> Vec<serde_json::Value> {
 200→    let Some(ref metadata) = gw.services.session_metadata else {
 201→        return Vec::new();
 202→    };
 203→
 204→    let mut recent = Vec::new();
 205→    for entry in metadata.list().await.into_iter().take(limit) {
 206→        let active_channel = if let Some(ref binding_json) = entry.channel_binding {
 207→            if let Ok(target) =
 208→                serde_json::from_str::<moltis_channels::ChannelReplyTarget>(binding_json)
 209→            {
 210→                metadata
 211→                    .get_active_session(
 212→                        target.channel_type.as_str(),
 213→                        &target.account_id,
 214→                        &target.chat_id,
 215→                        target.thread_id.as_deref(),
 216→                    )
 217→                    .await
 218→                    .unwrap_or_else(|| default_channel_session_key(&target))
 219→                    == entry.key
 220→            } else {
 221→                false
 222→            }
 223→        } else {
 224→            false
 225→        };
 226→        let preview = entry
 227→            .preview
 228→            .as_deref()
 229→            .map(|text| truncate_preview(text, SESSION_PREVIEW_MAX_CHARS));
 230→        let agent_id = entry.agent_id.clone().unwrap_or_else(|| "main".to_owned());
 231→        let agent_id_camel = agent_id.clone();
 232→
 233→        recent.push(serde_json::json!({
 234→            "id": entry.id,
 235→            "key": entry.key,
 236→            "label": entry.label,
 237→            "model": entry.model,
 238→            "createdAt": entry.created_at,
 239→            "updatedAt": entry.updated_at,
 240→            "messageCount": entry.message_count,
 241→            "lastSeenMessageCount": entry.last_seen_message_count,
 242→            "projectId": entry.project_id,
 243→            "sandbox_enabled": entry.sandbox_enabled,
 244→            "sandbox_image": entry.sandbox_image,
 245→            "worktree_branch": entry.worktree_branch,
 246→            "channelBinding": entry.channel_binding,
 247→            "activeChannel": active_channel,
 248→            "parentSessionKey": entry.parent_session_key,
 249→            "forkPoint": entry.fork_point,
 250→            "mcpDisabled": entry.mcp_disabled,
 251→            "preview": preview,
 252→            "archived": entry.archived,
 253→            "agent_id": agent_id,
 254→            "agentId": agent_id_camel,
 255→            "node_id": entry.node_id,
 256→            "version": entry.version,
 257→        }));
 258→    }
 259→
 260→    recent
 261→}
