 265→#[derive(Debug, Default, serde::Serialize)]
 266→pub(crate) struct NavCounts {
 267→    projects: usize,
 268→    providers: usize,
 269→    channels: usize,
 270→    skills: usize,
 271→    mcp: usize,
 272→    crons: usize,
 273→    hooks: usize,
 274→}
