 276→pub(crate) async fn build_nav_counts(gw: &GatewayState) -> NavCounts {
 277→    let (projects, models, channels, mcp, crons) = tokio::join!(
 278→        gw.services.project.list(),
 279→        gw.services.model.list(),
 280→        gw.services.channel.status(),
 281→        gw.services.mcp.list(),
 282→        gw.services.cron.list(),
 283→    );
 284→
 285→    let projects = projects
 286→        .ok()
 287→        .and_then(|v| v.as_array().map(|a| a.len()))
 288→        .unwrap_or(0);
 289→
 290→    let providers = models
 291→        .ok()
 292→        .and_then(|v| {
 293→            v.as_array().map(|arr| {
 294→                let mut names: HashSet<&str> = HashSet::new();
 295→                for m in arr {
 296→                    if let Some(p) = m.get("provider").and_then(|p| p.as_str()) {
 297→                        names.insert(p);
 298→                    }
 299→                }
 300→                names.len()
 301→            })
 302→        })
 303→        .unwrap_or(0);
 304→
 305→    let channels = channels
 306→        .ok()
 307→        .and_then(|v| {
 308→            v.get("channels")
 309→                .and_then(|c| c.as_array())
 310→                .map(|a| a.len())
 311→        })
 312→        .unwrap_or(0);
 313→
 314→    let mut skills = 0usize;
 315→    if let Ok(path) = moltis_skills::manifest::ManifestStore::default_path() {
 316→        let store = moltis_skills::manifest::ManifestStore::new(path);
 317→        if let Ok(m) = store.load() {
 318→            skills = m
 319→                .repos
 320→                .iter()
 321→                .flat_map(|r| &r.skills)
 322→                .filter(|s| s.enabled)
 323→                .count();
 324→        }
 325→    }
 326→
 327→    let mcp = mcp
 328→        .ok()
 329→        .and_then(|v| {
 330→            v.as_array().map(|arr| {
 331→                arr.iter()
 332→                    .filter(|s| s.get("state").and_then(|s| s.as_str()) == Some("running"))
 333→                    .count()
 334→            })
 335→        })
 336→        .unwrap_or(0);
 337→
 338→    let crons = crons
 339→        .ok()
 340→        .and_then(|v| {
 341→            v.as_array().map(|arr| {
 342→                arr.iter()
 343→                    .filter(|j| {
 344→                        let enabled = j.get("enabled").and_then(|e| e.as_bool()).unwrap_or(false);
 345→                        let system = j.get("system").and_then(|s| s.as_bool()).unwrap_or(false);
 346→                        enabled && !system
 347→                    })
 348→                    .count()
 349→            })
 350→        })
 351→        .unwrap_or(0);
 352→
 353→    let hooks = gw.inner.read().await.discovered_hooks.len();
 354→
 355→    NavCounts {
 356→        projects,
 357→        providers,
 358→        channels,
 359→        skills,
 360→        mcp,
 361→        crons,
 362→        hooks,
 363→    }
 364→}
