 368→pub(crate) async fn build_gon_data(gw: &GatewayState) -> GonData {
 369→    const GON_SESSIONS_RECENT_LIMIT: usize = 30;
 370→
 371→    let port = gw.port;
 372→    let identity = gw
 373→        .services
 374→        .onboarding
 375→        .identity_get()
 376→        .await
 377→        .ok()
 378→        .and_then(|v| serde_json::from_value(v).ok())
 379→        .unwrap_or_default();
 380→
 381→    let counts = build_nav_counts(gw).await;
 382→    let (crons, cron_status, webhooks_val, webhook_profiles_val) = tokio::join!(
 383→        gw.services.cron.list(),
 384→        gw.services.cron.status(),
 385→        gw.services.webhooks.list(),
 386→        gw.services.webhooks.profiles(),
 387→    );
 388→    let webhooks: Vec<serde_json::Value> = webhooks_val
 389→        .ok()
 390→        .and_then(|v| serde_json::from_value(v).ok())
 391→        .unwrap_or_default();
 392→    let webhook_profiles: Vec<serde_json::Value> = webhook_profiles_val
 393→        .ok()
 394→        .and_then(|v| serde_json::from_value(v).ok())
 395→        .unwrap_or_default();
 396→    let crons: Vec<moltis_cron::types::CronJob> = crons
 397→        .ok()
 398→        .and_then(|v| serde_json::from_value(v).ok())
 399→        .unwrap_or_default();
 400→    let cron_status: moltis_cron::types::CronStatus = cron_status
 401→        .ok()
 402→        .and_then(|v| serde_json::from_value(v).ok())
 403→        .unwrap_or_default();
 404→    let (heartbeat_config, cached_channels_offered) = {
 405→        let inner = gw.inner.read().await;
 406→        (
 407→            inner.heartbeat_config.clone(),
 408→            inner.channels_offered.clone(),
 409→        )
 410→    };
 411→    let channels_offered = resolve_channels_offered(cached_channels_offered);
 412→    let channel_descriptors: Vec<moltis_channels::ChannelDescriptor> = channels_offered
 413→        .iter()
 414→        .filter_map(|s| s.parse::<moltis_channels::ChannelType>().ok())
 415→        .map(|ct| ct.descriptor())
 416→        .collect();
 417→
 418→    let heartbeat_runs: Vec<moltis_cron::types::CronRunRecord> = gw
 419→        .services
 420→        .cron
 421→        .runs(serde_json::json!({ "id": "__heartbeat__", "limit": 10 }))
 422→        .await
 423→        .ok()
 424→        .and_then(|v| serde_json::from_value(v).ok())
 425→        .unwrap_or_default();
 426→
 427→    let sandbox = if let Some(ref router) = gw.sandbox_router {
 428→        SandboxGonInfo {
 429→            backend: router.backend_name().to_owned(),
 430→            os: std::env::consts::OS,
 431→            default_image: router.default_image().await,
 432→            image_building: router
 433→                .building_flag
 434→                .load(std::sync::atomic::Ordering::Relaxed),
 435→        }
 436→    } else {
 437→        SandboxGonInfo {
 438→            backend: "none".to_owned(),
 439→            os: std::env::consts::OS,
 440→            default_image: moltis_tools::sandbox::DEFAULT_SANDBOX_IMAGE.to_owned(),
 441→            image_building: false,
 442→        }
 443→    };
 444→
 445→    // Fetch agent personas for the gon data.
 446→    let agents: Vec<serde_json::Value> = if let Some(ref store) = gw.services.agent_persona_store {
 447→        store
 448→            .list()
 449→            .await
 450→            .ok()
 451→            .map(|list| {
 452→                list.into_iter()
 453→                    .map(|a| serde_json::to_value(a).unwrap_or_default())
 454→                    .collect()
 455→            })
 456→            .unwrap_or_default()
 457→    } else {
 458→        Vec::new()
 459→    };
 460→
 461→    let sessions_recent = build_recent_sessions_snapshot(gw, GON_SESSIONS_RECENT_LIMIT).await;
 462→
 463→    GonData {
 464→        identity,
 465→        version: gw.version.clone(),
 466→        port,
 467→        counts,
 468→        crons,
 469→        cron_status,
 470→        heartbeat_config,
 471→        heartbeat_runs,
 472→        voice_enabled: cfg!(feature = "voice"),
 473→        graphql_enabled: cfg!(feature = "graphql"),
 474→        terminal_enabled: gw.config.server.is_terminal_enabled(),
 475→        git_branch: detect_git_branch(),
 476→        mem: collect_mem_snapshot(),
 477→        deploy_platform: gw.deploy_platform.clone(),
 478→        channels_offered,
 479→        channel_descriptors,
 480→        channel_storage_db_path: moltis_config::data_dir()
 481→            .join("moltis.db")
 482→            .display()
 483→            .to_string(),
 484→        update: gw.inner.read().await.update.clone(),
 485→        sandbox,
 486→        routes: SPA_ROUTES.clone(),
 487→        started_at: *PROCESS_STARTED_AT_MS,
 488→        openclaw_detected: moltis_gateway::server::openclaw_detected_for_ui(),
 489→        sessions_recent,
 490→        agents,
 491→        webhooks,
 492→        webhook_profiles,
 493→        #[cfg(feature = "vault")]
 494→        vault_status: {
 495→            if let Some(ref vault) = gw.vault {
 496→                match vault.status().await {
 497→                    Ok(s) => format!("{s:?}").to_lowercase(),
 498→                    Err(_) => "error".to_owned(),
 499→                }
 500→            } else {
 501→                "disabled".to_owned()
 502→            }
 503→        },
 504→    }
 505→}
