 507→fn load_channels_offered_from_config_path(
 508→    path: &Path,
 509→) -> Result<Vec<String>, moltis_config::Error> {
 510→    moltis_config::loader::load_config(path).map(|config| config.channels.offered)
 511→}
 512→
 513→fn resolve_channels_offered(cached_channels_offered: Vec<String>) -> Vec<String> {
 514→    let Some(path) = moltis_config::loader::find_config_file() else {
 515→        return cached_channels_offered;
 516→    };
 517→
 518→    match load_channels_offered_from_config_path(&path) {
 519→        Ok(channels_offered) => channels_offered,
 520→        Err(error) => {
 521→            warn!(
 522→                path = %path.display(),
 523→                error = %error,
 524→                "failed to reload channels.offered for gon data, using startup value"
 525→            );
 526→            cached_channels_offered
 527→        },
 528→    }
 529→}
