 700→fn insert_standard_headers(response: &mut axum::response::Response, csp: &str) {
 701→    let headers = response.headers_mut();
 702→    if let Ok(val) = "no-cache, no-store".parse() {
 703→        headers.insert(axum::http::header::CACHE_CONTROL, val);
 704→    }
 705→    if let Ok(val) = csp.parse() {
 706→        headers.insert(axum::http::header::CONTENT_SECURITY_POLICY, val);
 707→    }
 708→}
