 710→fn trim_route_path(path: &str) -> &str {
 711→    if path.len() > 1 {
 712→        path.trim_end_matches('/')
 713→    } else {
 714→        path
 715→    }
 716→}
 717→
 718→fn matches_exact_or_nested(path: &str, base: &str) -> bool {
 719→    path == base
 720→        || path
 721→            .strip_prefix(base)
 722→            .is_some_and(|suffix| suffix.starts_with('/'))
 723→}
 724→
 725→pub(crate) fn is_known_spa_route(path: &str) -> bool {
 726→    let path = trim_route_path(path);
 727→    path == "/"
 728→        || matches_exact_or_nested(path, SPA_ROUTES.projects)
 729→        || matches_exact_or_nested(path, SPA_ROUTES.skills)
 730→        || matches_exact_or_nested(path, SPA_ROUTES.chats)
 731→        || matches_exact_or_nested(path, SPA_ROUTES.settings)
 732→        || matches_exact_or_nested(path, SPA_ROUTES.monitoring)
 733→}
