 735→pub(crate) fn render_error_page(
 736→    status: StatusCode,
 737→    kind: ErrorPageKind,
 738→    _requested_path: Option<&str>,
 739→) -> axum::response::Response {
 740→    let asset_prefix = build_asset_prefix();
 741→    let nonce = build_nonce();
 742→    let (page_title, eyebrow, message) = match kind {
 743→        ErrorPageKind::NotFound => ("Page not found", "404", "This page could not be found."),
 744→        ErrorPageKind::InternalServerError => (
 745→            "Internal server error",
 746→            "500",
 747→            "Moltis hit an internal error while building this page.",
 748→        ),
 749→    };
 750→
 751→    let template = ErrorHtmlTemplate {
 752→        asset_prefix: &asset_prefix,
 753→        nonce: &nonce,
 754→        page_title,
 755→        eyebrow,
 756→        message,
 757→    };
 758→
 759→    let body = match template.render() {
 760→        Ok(html) => html,
 761→        Err(error) => {
 762→            warn!(%error, ?status, "failed to render error template");
 763→            format!(
 764→                "<!doctype html><html lang=\"en\"><head><meta charset=\"utf-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1\"><title>{status} {page_title}</title></head><body><h1>{eyebrow}</h1><p>{message}</p><p><a href=\"/\">Go home</a></p></body></html>",
 765→            )
 766→        },
 767→    };
 768→
 769→    let csp = format!(
 770→        "default-src 'self'; \
 771→         script-src 'self' 'nonce-{nonce}'; \
 772→         style-src 'self' 'unsafe-inline'; \
 773→         img-src 'self' data:; \
 774→         font-src 'self'; \
 775→         frame-ancestors 'none'; \
 776→         form-action 'self'; \
 777→         base-uri 'self'; \
 778→         object-src 'none'",
 779→    );
 780→
 781→    let mut response = (status, Html(body)).into_response();
 782→    insert_standard_headers(&mut response, &csp);
 783→    response
 784→}
