 786→pub(crate) async fn render_spa_template(
 787→    gateway: &GatewayState,
 788→    template: SpaTemplate,
 789→) -> axum::response::Response {
 790→    let build_ts = if is_dev_assets() {
 791→        "dev".to_owned()
 792→    } else {
 793→        asset_content_hash()
 794→    };
 795→    let asset_prefix = build_asset_prefix();
 796→    let nonce = build_nonce();
 797→
 798→    // Resolve Shiki URL from config override or default CDN.
 799→    let shiki_url = gateway
 800→        .inner
 801→        .read()
 802→        .await
 803→        .shiki_cdn_url
 804→        .clone()
 805→        .unwrap_or_else(|| DEFAULT_SHIKI_CDN_URL.to_owned());
 806→
 807→    let body = match template {
 808→        SpaTemplate::Index => {
 809→            let gon = build_gon_data(gateway).await;
 810→            let share_meta = build_share_meta(&gon.identity);
 811→            let gon_json = script_safe_json(&gon);
 812→            let template = IndexHtmlTemplate {
 813→                build_ts: &build_ts,
 814→                asset_prefix: &asset_prefix,
 815→                nonce: &nonce,
 816→                gon_json: &gon_json,
 817→                share_title: &share_meta.title,
 818→                share_description: &share_meta.description,
 819→                share_site_name: &share_meta.site_name,
 820→                share_image_url: SHARE_IMAGE_URL,
 821→                share_image_alt: &share_meta.image_alt,
 822→                routes: &SPA_ROUTES,
 823→                shiki_url: &shiki_url,
 824→            };
 825→            match template.render() {
 826→                Ok(html) => html,
 827→                Err(e) => {
 828→                    warn!(error = %e, "failed to render index template");
 829→                    return render_error_page(
 830→                        StatusCode::INTERNAL_SERVER_ERROR,
 831→                        ErrorPageKind::InternalServerError,
 832→                        None,
 833→                    );
 834→                },
 835→            }
 836→        },
 837→        SpaTemplate::Login => {
 838→            let gon = build_gon_data(gateway).await;
 839→            let gon_json = script_safe_json(&gon);
 840→            let page_title = identity_name(&gon.identity).to_owned();
 841→            let template = LoginHtmlTemplate {
 842→                build_ts: &build_ts,
 843→                asset_prefix: &asset_prefix,
 844→                nonce: &nonce,
 845→                page_title: &page_title,
 846→                gon_json: &gon_json,
 847→            };
 848→            match template.render() {
 849→                Ok(html) => html,
 850→                Err(e) => {
 851→                    warn!(error = %e, "failed to render login template");
 852→                    return render_error_page(
 853→                        StatusCode::INTERNAL_SERVER_ERROR,
 854→                        ErrorPageKind::InternalServerError,
 855→                        None,
 856→                    );
 857→                },
 858→            }
 859→        },
 860→        SpaTemplate::Onboarding => {
 861→            let gon = build_gon_data(gateway).await;
 862→            let gon_json = script_safe_json(&gon);
 863→            let page_title = format!("{} onboarding", identity_name(&gon.identity));
 864→            let template = OnboardingHtmlTemplate {
 865→                build_ts: &build_ts,
 866→                asset_prefix: &asset_prefix,
 867→                nonce: &nonce,
 868→                page_title: &page_title,
 869→                gon_json: &gon_json,
 870→            };
 871→            match template.render() {
 872→                Ok(html) => html,
 873→                Err(e) => {
 874→                    warn!(error = %e, "failed to render onboarding template");
 875→                    return render_error_page(
 876→                        StatusCode::INTERNAL_SERVER_ERROR,
 877→                        ErrorPageKind::InternalServerError,
 878→                        None,
 879→                    );
 880→                },
 881→            }
 882→        },
 883→        SpaTemplate::SetupRequired => {
 884→            let template = SetupRequiredHtmlTemplate {
 885→                asset_prefix: &asset_prefix,
 886→            };
 887→            match template.render() {
 888→                Ok(html) => html,
 889→                Err(e) => {
 890→                    warn!(error = %e, "failed to render setup-required template");
 891→                    return render_error_page(
 892→                        StatusCode::INTERNAL_SERVER_ERROR,
 893→                        ErrorPageKind::InternalServerError,
 894→                        None,
 895→                    );
 896→                },
 897→            }
 898→        },
 899→    };
 900→
 901→    // Extract CDN origin from shiki_url for CSP script-src allowlisting.
 902→    let shiki_csp_origin = url::Url::parse(&shiki_url)
 903→        .ok()
 904→        .and_then(|u| u.host_str().map(|host| format!("{}://{host}", u.scheme())));
 905→
 906→    let csp = format!(
 907→        "default-src 'self'; \
 908→         script-src 'self' 'nonce-{nonce}' 'wasm-unsafe-eval'{shiki_origin}; \
 909→         style-src 'self' 'unsafe-inline'; \
 910→         img-src 'self' data: blob:; \
 911→         media-src 'self' blob:; \
 912→         font-src 'self'; \
 913→         connect-src 'self' ws: wss:; \
 914→         frame-ancestors 'none'; \
 915→         form-action 'self'; \
 916→         base-uri 'self'; \
 917→         object-src 'none'",
 918→        shiki_origin = shiki_csp_origin
 919→            .as_deref()
 920→            .map(|o| format!(" {o}"))
 921→            .unwrap_or_default(),
 922→    );
 923→
 924→    let mut response = Html(body).into_response();
 925→    insert_standard_headers(&mut response, &csp);
 926→    response
 927→}
