  83→function slashShowMenu(filter) {
  84→	slashInjectStyles();
  85→	var matches = slashCommands.filter((c) => `/${c.name}`.indexOf(filter) === 0);
  86→	if (matches.length === 0) {
  87→		slashHideMenu();
  88→		return;
  89→	}
  90→	slashMenuItems = matches;
  91→	slashMenuIdx = 0;
  92→
  93→	if (!slashMenuEl) {
  94→		slashMenuEl = document.createElement("div");
  95→		slashMenuEl.className = "slash-menu";
  96→	}
  97→	while (slashMenuEl.firstChild) slashMenuEl.removeChild(slashMenuEl.firstChild);
  98→	matches.forEach((cmd, i) => {
  99→		var item = document.createElement("div");
 100→		item.className = `slash-menu-item${i === 0 ? " active" : ""}`;
 101→		var nameSpan = document.createElement("span");
 102→		nameSpan.className = "slash-name";
 103→		nameSpan.textContent = `/${cmd.name}`;
 104→		var descSpan = document.createElement("span");
 105→		descSpan.className = "slash-desc";
 106→		descSpan.textContent = cmd.description;
 107→		item.appendChild(nameSpan);
 108→		item.appendChild(descSpan);
 109→		item.addEventListener("mousedown", (e) => {
 110→			e.preventDefault();
 111→			slashSelectItem(i);
 112→		});
 113→		slashMenuEl.appendChild(item);
 114→	});
 115→
 116→	var inputWrap = S.chatInput.parentElement;
 117→	if (inputWrap && !slashMenuEl.parentElement) {
 118→		inputWrap.classList.add("relative");
 119→		inputWrap.appendChild(slashMenuEl);
 120→	}
 121→}
