 147→function slashHandleKeydown(e) {
 148→	if (!slashMenuEl?.parentElement || slashMenuItems.length === 0) return false;
 149→	if (e.key === "ArrowUp") {
 150→		e.preventDefault();
 151→		slashMenuIdx = (slashMenuIdx - 1 + slashMenuItems.length) % slashMenuItems.length;
 152→		slashUpdateActive();
 153→		return true;
 154→	}
 155→	if (e.key === "ArrowDown") {
 156→		e.preventDefault();
 157→		slashMenuIdx = (slashMenuIdx + 1) % slashMenuItems.length;
 158→		slashUpdateActive();
 159→		return true;
 160→	}
 161→	if (e.key === "Enter" || e.key === "Tab") {
 162→		e.preventDefault();
 163→		slashSelectItem(slashMenuIdx);
 164→		return true;
 165→	}
 166→	if (e.key === "Escape") {
 167→		e.preventDefault();
 168→		slashHideMenu();
 169→		return true;
 170→	}
 171→	return false;
 172→}
