 182→function parseSlashCommand(text) {
 183→	if (!text || text.charAt(0) !== "/") return null;
 184→	var body = text.substring(1).trim();
 185→	if (!body) return null;
 186→	var spaceIdx = body.indexOf(" ");
 187→	if (spaceIdx === -1) {
 188→		return { name: body.toLowerCase(), args: "" };
 189→	}
 190→	return {
 191→		name: body.substring(0, spaceIdx).toLowerCase(),
 192→		args: body.substring(spaceIdx + 1).trim(),
 193→	};
 194→}
