 196→function isShLocalToggle(args) {
 197→	if (!args) return true;
 198→	var normalized = args.toLowerCase();
 199→	return normalized === "on" || normalized === "off" || normalized === "exit";
 200→}
 201→
 202→function shouldHandleSlashLocally(cmdName, args) {
 203→	if (cmdName === "sh") {
 204→		return isShLocalToggle(args);
 205→	}
 206→	return slashCommands.some((c) => c.name === cmdName);
 207→}
