 253→function buildPromptMemorySummary(promptMemory) {
 254→	if (!promptMemory) return "Unavailable";
 255→	var parts = [formatPromptMemoryMode(promptMemory.mode)];
 256→	if (promptMemory.snapshotActive) {
 257→		parts.push("snapshot active");
 258→	}
 259→	parts.push(promptMemory.present ? `${Number(promptMemory.chars || 0).toLocaleString()} chars` : "empty");
 260→	return parts.join(" · ");
 261→}
