 263→function promptMemoryDetailParts(promptMemory) {
 264→	if (!promptMemory) return [];
 265→	var parts = [];
 266→	if (promptMemory.fileSource) parts.push(`source ${formatPromptMemorySource(promptMemory.fileSource)}`);
 267→	if (promptMemory.path) parts.push(promptMemory.path);
 268→	return parts;
