 271→function promptMemoryToolbarTitle(promptMemory) {
 272→	if (!promptMemory) return "Prompt memory unavailable";
 273→	var parts = [`Prompt memory: ${buildPromptMemorySummary(promptMemory)}`];
 274→	var detailParts = promptMemoryDetailParts(promptMemory);
 275→	if (detailParts.length > 0) parts.push(detailParts.join(" · "));
 276→	return parts.join("\n");
