 286→function setPromptMemoryToolbarState(promptMemory, loading, refreshing) {
 287→	var toolbar = S.$("promptMemoryToolbar");
 288→	var statusBtn = S.$("promptMemoryStatusBtn");
 289→	var statusLabel = S.$("promptMemoryStatusLabel");
 290→	var refreshBtn = S.$("promptMemoryRefreshBtn");
 291→	if (!(toolbar && statusBtn && statusLabel && refreshBtn)) return;
 292→	toolbar.classList.remove("hidden");
 293→	toolbar.classList.add("inline-flex");
 294→	statusBtn.disabled = !!loading;
 295→	refreshBtn.disabled = !!refreshing;
 296→	if (loading) {
 297→		statusLabel.textContent = "Memory…";
 298→		statusBtn.title = "Loading prompt memory status";
 299→		refreshBtn.classList.add("hidden");
 300→		return;
 301→	}
 302→	statusLabel.textContent = promptMemoryToolbarLabel(promptMemory);
 303→	statusBtn.title = promptMemoryToolbarTitle(promptMemory);
 304→	refreshBtn.classList.toggle("hidden", promptMemory?.mode !== "frozen-at-session-start");
 305→	refreshBtn.title =
 306→		promptMemory?.mode === "frozen-at-session-start" ? "Refresh frozen prompt memory" : "Refresh unavailable";
 307→}
