 313→function refreshPromptMemoryToolbar() {
 314→	if (!S.connected) {
 315→		setPromptMemoryToolbarState(null, false, false);
 316→		return Promise.resolve(null);
 317→	}
 318→	var requestId = ++promptMemoryToolbarRequestId;
 319→	setPromptMemoryToolbarState(null, true, false);
 320→	return sendRpc("chat.context", {}).then((res) => {
 321→		if (requestId !== promptMemoryToolbarRequestId) return null;
 322→		if (res?.ok && res.payload) {
 323→			var promptMemory = res.payload.promptMemory || null;
 324→			refreshPromptMemoryToolbarFromPayload(promptMemory);
 325→			return promptMemory;
 326→		}
 327→		setPromptMemoryToolbarState(null, false, false);
 328→		return null;
 329→	});
 330→}
 331→
 332→function refreshPromptMemoryToolbarSnapshot() {
 333→	setPromptMemoryToolbarState(null, false, true);
 334→	return sendRpc("chat.prompt_memory.refresh", {})
 335→		.then((res) => {
 336→			if (!(res?.ok && res.payload)) {
 337→				throw new Error(res?.error?.message || "Failed to refresh prompt memory");
 338→			}
 339→			var promptMemory = res.payload.promptMemory || null;
 340→			refreshPromptMemoryToolbarFromPayload(promptMemory);
 341→			maybeRefreshFullContext();
 342→			return promptMemory;
 343→		})
 344→		.catch((error) => {
 345→			refreshPromptMemoryToolbar();
 346→			chatAddMsg("error", error?.message || "Failed to refresh prompt memory");
 347→			return null;
 348→		});
 349→}
