1077→// ── Slash command handlers ───────────────────────────────
1078→function handleSlashCommand(cmdName, cmdArgs) {
1079→	if (cmdName === "clear") {
1080→		clearActiveSession();
1081→		return;
1082→	}
1083→	if (cmdName === "compact") {
1084→		chatAddMsg("system", "Compacting conversation\u2026");
1085→		sendRpc("chat.compact", {}).then((res) => {
1086→			if (res?.ok) {
1087→				switchSession(S.activeSessionKey);
1088→			} else {
1089→				chatAddMsg("error", res?.error?.message || "Compact failed");
1090→			}
1091→		});
1092→		return;
1093→	}
1094→	if (cmdName === "context") {
1095→		chatAddMsg("system", "Loading context\u2026");
1096→		sendRpc("chat.context", {}).then((res) => {
1097→			if (S.chatMsgBox?.lastChild) S.chatMsgBox.removeChild(S.chatMsgBox.lastChild);
1098→			if (res?.ok && res.payload) {
1099→				try {
1100→					renderContextCard(res.payload);
1101→				} catch (err) {
1102→					chatAddMsg("error", `Render error: ${err.message}`);
1103→				}
1104→			} else {
1105→				chatAddMsg("error", res?.error?.message || "Context failed");
1106→			}
1107→		});
1108→		return;
1109→	}
1110→	if (cmdName === "sh") {
1111→		var normalized = (cmdArgs || "").toLowerCase();
1112→		if (normalized === "off" || normalized === "exit") {
1113→			setCommandMode(false);
1114→			chatAddMsg("system", renderMarkdown("**Command:** mode disabled"), true);
1115→			return;
1116→		}
1117→		setCommandMode(true);
1118→		chatAddMsg(
1119→			"system",
1120→			renderMarkdown(`**Command:** mode enabled (${commandModeSummary()}) · exit with /sh off or Esc`),
1121→			true,
1122→		);
1123→	}
1124→}
