1200→// ── Send chat message ────────────────────────────────────
1201→function sendChat() {
1202→	var text = S.chatInput.value.trim();
1203→	var hasImages = hasPendingImages();
1204→	if (!((text || hasImages) && S.connected)) return;
1205→
1206→	// Unlock audio playback while we still have user-gesture context.
1207→	warmAudioPlayback();
1208→
1209→	if (tryHandleLocalSlashCommand(text, hasImages)) return;
