1404→function handleChatCopy(e) {
1405→	var sel = window.getSelection();
1406→	if (!sel || sel.isCollapsed || !S.chatMsgBox) return;
1407→
1408→	var lines = [];
1409→	for (var msg of S.chatMsgBox.querySelectorAll(".msg")) {
1410→		if (!sel.containsNode(msg, true)) continue;
1411→		var role = msgRole(msg);
1412→		if (!role) continue;
1413→		var text = sel.containsNode(msg, false) ? msg.textContent.trim() : sel.toString().trim();
1414→		if (text) lines.push(`${role}:\n${text}`);
1415→	}
1416→	if (lines.length > 1) {
1417→		e.preventDefault();
1418→		e.clipboardData.setData("text/plain", lines.join("\n\n"));
1419→	}
1420→}
