 1→// ── Model store (signal-based) ──────────────────────────────
 2→//
 3→// Single source of truth for model data. Both Preact components
 4→// (auto-subscribe) and imperative code (read .value) can use this.
 5→
 6→import { computed, signal } from "@preact/signals";
 7→import { sendRpc } from "../helpers.js";
 8→
 9→// ── Signals ──────────────────────────────────────────────────
10→export var models = signal([]);
11→export var selectedModelId = signal(localStorage.getItem("moltis-model") || "");
12→
13→export var selectedModel = computed(() => {
14→	var id = selectedModelId.value;
15→	return models.value.find((m) => m.id === id) || null;
16→});
17→
18→// ── Methods ──────────────────────────────────────────────────
19→
20→/** Replace the full model list (e.g. after fetch or bootstrap). */
21→export function setAll(arr) {
22→	models.value = arr || [];
23→}
24→
25→/** Fetch models from the server via RPC. */
26→export function fetch() {
27→	return sendRpc("models.list", {}).then((res) => {
28→		if (!res?.ok) return;
29→		setAll(res.payload || []);
30→		if (models.value.length === 0) return;
31→		var saved = localStorage.getItem("moltis-model") || "";
32→		var found = models.value.find((m) => m.id === saved);
33→		var model = found || models.value[0];
34→		select(model.id);
35→		if (!found) localStorage.setItem("moltis-model", model.id);
36→	});
37→}
38→
39→/** Select a model by id. Persists to localStorage. */
40→export function select(id) {
41→	selectedModelId.value = id;
42→}
43→
44→/** Look up a model by id. */
45→export function getById(id) {
46→	return models.value.find((m) => m.id === id) || null;
47→}
48→
49→export var modelStore = { models, selectedModelId, selectedModel, setAll, fetch, select, getById };
