 603→export function renderCompactCard(data) {
 604→	if (!S.chatMsgBox) return;
 605→	slashInjectStyles();
 606→
 607→	var card = ctxEl("div", "ctx-card");
 608→
 609→	var header = ctxEl("div", "ctx-header");
 610→	var icon = document.createElement("span");
 611→	icon.className = "icon icon-compress";
 612→	header.appendChild(icon);
 613→	header.appendChild(ctxEl("span", "ctx-header-title", "Conversation compacted"));
 614→	card.appendChild(header);
 615→
 616→	// Strategy section — surfaces the mode that actually ran and the LLM
 617→	// token spend so users can see why compaction was fast/slow and what
 618→	// it cost. Fields come from CompactionOutcome::broadcast_metadata()
 619→	// on the Rust side.
 620→	if (data.mode) {
 621→		var strategySection = ctxSection("Strategy");
 622→		strategySection.appendChild(ctxRow("Mode", compactionModeLabel(data.mode)));
 623→		var totalTokens = Number(data.compactionTotalTokens || 0);
 624→		if (totalTokens > 0) {
 625→			var inputTokens = Number(data.compactionInputTokens || 0);
 626→			var outputTokens = Number(data.compactionOutputTokens || 0);
 627→			strategySection.appendChild(
 628→				ctxRow(
 629→					"Tokens used",
 630→					`${formatTokens(totalTokens)} (${formatTokens(inputTokens)} in + ${formatTokens(outputTokens)} out)`,
 631→				),
 632→			);
 633→		} else {
 634→			strategySection.appendChild(ctxRow("Tokens used", "0 (no LLM call)"));
 635→		}
 636→		card.appendChild(strategySection);
 637→	}
 638→
 639→	var statsSection = ctxSection("Before compact");
 640→	statsSection.appendChild(ctxRow("Messages", String(data.messageCount || 0)));
 641→	if (data.totalTokens) {
 642→		statsSection.appendChild(ctxRow("Total tokens", formatTokens(data.totalTokens || 0)));
 643→	}
 644→	if (data.estimatedNextInputTokens) {
 645→		statsSection.appendChild(ctxRow("Estimated next input", formatTokens(data.estimatedNextInputTokens), true));
 646→	}
 647→	if (data.contextWindow) {
 648→		var basis = data.estimatedNextInputTokens || data.totalTokens || 0;
 649→		var pctUsed = Math.round((basis / data.contextWindow) * 100);
 650→		statsSection.appendChild(ctxRow("Context usage", `${pctUsed}% of ${formatTokens(data.contextWindow)}`));
 651→	}
 652→	card.appendChild(statsSection);
 653→
 654→	// "After compact" messaging depends on the mode: deterministic /
 655→	// llm_replace collapse to a single summary message, while
 656→	// recency_preserving / structured splice the summary between head
 657→	// and tail so multiple messages survive.
 658→	var afterSection = ctxSection("After compact");
 659→	var replacesAll = data.mode === "deterministic" || data.mode === "llm_replace" || !data.mode;
 660→	if (replacesAll) {
 661→		afterSection.appendChild(ctxRow("Messages", "1 (summary)"));
 662→		afterSection.appendChild(ctxRow("Status", "Conversation history replaced with a summary"));
 663→	} else {
 664→		afterSection.appendChild(ctxRow("Status", "Head + tail preserved verbatim; middle summarised"));
 665→	}
 666→	card.appendChild(afterSection);
 667→
 668→	// Settings hint — only rendered when the backend supplies one, so
 669→	// an older backend or a mode that doesn't emit it doesn't leave an
 670→	// empty row behind. The hint spans the full card width (not the
 671→	// two-column label/value ctx-row layout) so it reads like a
 672→	// tooltip/footnote.
 673→	if (data.settingsHint) {
 674→		var hintSection = ctxSection("Configure");
 675→		var hintRow = ctxEl("div", "ctx-value");
 676→		hintRow.textContent = data.settingsHint;
 677→		hintSection.appendChild(hintRow);
 678→		card.appendChild(hintSection);
 679→	}
 680→
 681→	S.chatMsgBox.appendChild(card);
 682→	S.chatMsgBox.scrollTop = S.chatMsgBox.scrollHeight;
 683→}
