 759→function ctxMsgMeta(msg, contentStr) {
 760→	var parts = [];
 761→	var chars = contentStr ? contentStr.length : 0;
 762→	if (chars > 0) parts.push(`${chars.toLocaleString()} chars`);
 763→	var toolCalls = msg.tool_calls || [];
 764→	if (toolCalls.length > 0) {
 765→		parts.push(`${toolCalls.length} tool call${toolCalls.length > 1 ? "s" : ""}`);
 766→	}
 767→	if (msg.role === "tool" && msg.tool_call_id) {
 768→		parts.push(`id: ${msg.tool_call_id}`);
 769→	}
 770→	return parts.join(" \xb7 ");
 771→}
