 773→function ctxMsgToolCall(tc) {
 774→	var div = ctxEl("div", "mt-1 border border-[var(--border)] rounded-md p-2 bg-[var(--surface)]");
 775→	var hdr = ctxEl("div", "text-xs font-semibold text-[var(--text)] mb-1");
 776→	hdr.textContent = `\ud83d\udee0 ${tc.function?.name || "unknown"}`;
 777→	if (tc.id) {
 778→		hdr.appendChild(ctxEl("span", "font-normal text-[var(--muted)] ml-2", `id: ${tc.id}`));
 779→	}
 780→	div.appendChild(hdr);
 781→	if (tc.function?.arguments) {
 782→		var pre = ctxEl("pre", "text-xs font-mono whitespace-pre-wrap break-words text-[var(--text)]");
 783→		try {
 784→			pre.textContent = JSON.stringify(JSON.parse(tc.function.arguments), null, 2);
 785→		} catch {
 786→			pre.textContent = tc.function.arguments;
 787→		}
 788→		div.appendChild(pre);
 789→	}
 790→	return div;
 791→}
