 793→function renderContextMessage(msg, index) {
 794→	var wrapper = ctxEl("div", "mb-2");
 795→	var contentStr = typeof msg.content === "string" ? msg.content : JSON.stringify(msg.content, null, 2);
 796→
 797→	// Header row: role badge + index + meta + chevron
 798→	var hdr = ctxEl("div", "flex items-center gap-2 cursor-pointer select-none");
 799→	hdr.appendChild(ctxMsgBadge(msg.role || "unknown"));
 800→	hdr.appendChild(ctxEl("span", "text-xs text-[var(--muted)]", `#${index}`));
 801→	var meta = ctxMsgMeta(msg, contentStr);
 802→	if (meta) hdr.appendChild(ctxEl("span", "text-xs text-[var(--muted)]", meta));
 803→	var chevron = ctxEl("span", "text-xs text-[var(--muted)] ml-auto");
 804→	var startOpen = index !== 0;
 805→	chevron.textContent = startOpen ? "\u25bc" : "\u25b6";
 806→	hdr.appendChild(chevron);
 807→	wrapper.appendChild(hdr);
 808→
 809→	// Collapsible body
 810→	var body = ctxEl("div", "mt-1");
 811→	body.style.display = startOpen ? "block" : "none";
 812→	hdr.addEventListener("click", () => {
 813→		var open = body.style.display !== "none";
 814→		body.style.display = open ? "none" : "block";
 815→		chevron.textContent = open ? "\u25b6" : "\u25bc";
 816→	});
 817→
 818→	if (contentStr) {
 819→		var pre = ctxEl(
 820→			"pre",
 821→			"text-xs font-mono whitespace-pre-wrap break-words bg-[var(--surface)] border border-[var(--border)] rounded-md p-2 text-[var(--text)]",
 822→		);
 823→		pre.textContent = contentStr;
 824→		body.appendChild(pre);
 825→	}
 826→	for (var tc of msg.tool_calls || []) body.appendChild(ctxMsgToolCall(tc));
 827→
 828→	wrapper.appendChild(body);
 829→	return wrapper;
 830→}
