 848→function appendFullContextWorkspaceWarnings(panel, payload) {
 849→	var workspaceFiles = Array.isArray(payload.workspaceFiles) ? payload.workspaceFiles : [];
 850→	if (!payload.truncated || workspaceFiles.length === 0) return;
 851→	var truncatedFiles = workspaceFiles.filter((file) => file?.truncated);
 852→	if (truncatedFiles.length === 0) return;
 853→	var warning = ctxEl(
 854→		"div",
 855→		"text-xs mb-3 rounded-md border border-[var(--border)] bg-[var(--surface)] p-2 text-[var(--text)]",
 856→	);
 857→	warning.textContent = truncatedFiles
 858→		.map((file) => {
 859→			var name = typeof file.name === "string" ? file.name : "workspace file";
 860→			var charCount = Number(file.original_chars || 0).toLocaleString();
 861→			var limitChars = Number(file.limit_chars || 0).toLocaleString();
 862→			var truncatedChars = Number(file.truncated_chars || 0).toLocaleString();
 863→			return `${name}: ${charCount} chars, limit ${limitChars}, truncated by ${truncatedChars}`;
 864→		})
 865→		.join(" | ");
