 896→function wireFullContextCopyButton(copyBtn, messages, llmOutputs, llmOutputPanel) {
 897→	copyBtn.addEventListener("click", () => {
 898→		var lines = messages.map((m) => {
 899→			var content = typeof m.content === "string" ? m.content : JSON.stringify(m.content);
 900→			var parts = [content];
 901→			for (var tc of m.tool_calls || []) {
 902→				parts.push(`[tool_call: ${tc.function?.name || "?"} ${tc.function?.arguments || ""}]`);
 903→			}
 904→			return `[${m.role}] ${parts.join("\n")}`;
