1179→// ── Build chat params (text-only or multimodal) ─────────
1180→function buildChatMessage(text, seq, displayText) {
1181→	var userText = displayText !== undefined ? displayText : text;
1182→	var images = hasPendingImages() ? getPendingImages() : [];
1183→	if (images.length > 0) {
1184→		var content = [];
1185→		if (text) content.push({ type: "text", text: text });
1186→		for (var img of images) {
1187→			content.push({ type: "image_url", image_url: { url: img.dataUrl } });
1188→		}
1189→		var params = { content: content, _seq: seq };
1190→		var el = chatAddMsgWithImages("user", userText ? renderMarkdown(userText) : "", images);
1191→		clearPendingImages();
1192→		return { params: params, el: el };
1193→	}
1194→	return {
1195→		params: { text: text, _seq: seq },
1196→		el: chatAddMsg("user", renderMarkdown(userText), true),
1197→	};
1198→}
