1200→// ── Send chat message ────────────────────────────────────
1201→function sendChat() {
1202→	var text = S.chatInput.value.trim();
1203→	var hasImages = hasPendingImages();
1204→	if (!((text || hasImages) && S.connected)) return;
1205→
1206→	// Unlock audio playback while we still have user-gesture context.
1207→	warmAudioPlayback();
1208→
1209→	if (tryHandleLocalSlashCommand(text, hasImages)) return;
1210→	rememberChatHistory(text);
1211→	resetComposerAfterSend();
1212→	var outgoingText = normalizeOutgoingText(text, hasImages);
1213→
1214→	S.setChatSeq(S.chatSeq + 1);
1215→	var msg = buildChatMessage(outgoingText, S.chatSeq, text);
1216→	var chatParams = msg.params;
1217→	var userEl = msg.el;
1218→	// Highlight code blocks in the user message (if any).
1219→	if (userEl) highlightCodeBlocks(userEl);
1220→
1221→	applySelectedModelToChatParams(chatParams);
1222→	bumpSessionCount(S.activeSessionKey, 1);
1223→	cacheOutgoingUserMessage(S.activeSessionKey, chatParams);
1224→	seedSessionPreviewFromUserText(S.activeSessionKey, text || outgoingText);
1225→	setSessionReplying(S.activeSessionKey, true);
1226→	sendRpc("chat.send", chatParams).then((res) => handleChatSendRpcResponse(res, userEl));
1227→	maybeRefreshFullContext();
1228→}
