				/>`,
			headerToolbarMount,
		);
	}
	var headerModalMount = S.$("sessionHeaderModalMount");
	if (headerModalMount) {
		render(
			html`<${SessionHeader}
					showSelectors=${false}
					showStop=${false}
					showFork=${false}
					showShare=${false}
					showDelete=${false}
					showArchive=${false}
					nameOwnLine=${true}
					showRenameButton=${true}
				/>`,
			headerModalMount,
		);
	}
	var headerModalTopMount = S.$("sessionHeaderModalTopMount");
	if (headerModalTopMount) {
