 1→const { expect, test } = require("../base-test");
 2→const { navigateAndWait, openChatMoreModal, waitForWsConnected, watchPageErrors } = require("../helpers");
 3→
 4→function isRetryableRpcError(message) {
 5→	if (typeof message !== "string") return false;
 6→	return message.includes("WebSocket not connected") || message.includes("WebSocket disconnected");
 7→}
 8→
 9→function isNoProvidersConfiguredResponse(response) {
10→	// `localizeRpcError` in helpers.js replaces `error.message` with a locale
11→	// string (e.g. "An internal server error occurred.") and moves the original
12→	// backend message to `serverMessage`. Check both so the test still skips
13→	// when providers are unconfigured.
14→	const err = response?.error;
15→	const message = err?.serverMessage || err?.message || "";
16→	return (
17→		err?.code === "UNAVAILABLE" ||
18→		message.includes("no LLM providers configured") ||
19→		message.includes("chat not configured")
20→	);
21→}
22→
23→function ignoreWaitError() {
24→	return "ignored";
25→}
26→
27→async function sendRpcFromPage(page, method, params) {
28→	let lastResponse = null;
29→	for (let attempt = 0; attempt < 30; attempt++) {
30→		if (attempt > 0) {
31→			await waitForWsConnected(page, 5_000).catch(ignoreWaitError);
32→		}
33→		lastResponse = await page
34→			.evaluate(
35→				async ({ methodName, methodParams }) => {
36→					var appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
37→					if (!appScript) throw new Error("app module script not found");
38→					var appUrl = new URL(appScript.src, window.location.origin);
39→					var prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
40→					var helpers = await import(`${prefix}js/helpers.js`);
41→					return helpers.sendRpc(methodName, methodParams);
42→				},
43→				{
44→					methodName: method,
45→					methodParams: params,
46→				},
47→			)
48→			.catch((error) => ({ ok: false, error: { message: error?.message || String(error) } }));
